import { Box, BoxSafeArea } from '@semparar/design-system-app';
import React from 'react';
import { Platform } from 'react-native';
import BasicScreen from '../../atomic/templates/BasicScreen';
import { LearnMoreRewardProgramViewProps } from './Models';
import FaqContent from '../../atomic/organisms/FaqContent';

const LearnMoreRewardProgramView: React.FC<LearnMoreRewardProgramViewProps> = ({
  data,
  title,
  onNavigation,
}) => {
  return (
    <BasicScreen
      leftIconOnPress={onNavigation}
      title="Saiba mais"
      hasScroll
      bgColor="BRAND_COMPLEMENT_03"
      errorButtonOnPress={onNavigation}
    >
      <BoxSafeArea align="flex-start" justify="flex-start" mode="padding" edges={['top']}>
        <Box mr="xs" ml="xs" mt={Platform.OS === 'android' ? 'small' : undefined}>
          <FaqContent items={data} title={title} />
        </Box>
      </BoxSafeArea>
    </BasicScreen>
  );
};

export default LearnMoreRewardProgramView;

